`, "",{"version":3,"sources":["webpack://./src/xjss/components/arts/ArtPageLayout.vue"],"names":[],"mappings":"AA2JA,2BACE,YAAa,CACb,qBAAsB,CACtB,WAAY,CACZ,eAAgB,CAChB,0EACF,CAEA,8BACE,YAAa,CACb,kBAAmB,CACnB,OAAQ,CACR,iBAAkB,CAClB,mHAA0H,CAC1H,6EAAiF,CACjF,aACF,CAEA,2BACE,YAAa,CACb,kBAAmB,CACnB,OAAQ,CACR,eAAgB,CAChB,WAAY,CACZ,iBAAkB,CAClB,sEAA0E,CAC1E,2DAA+D,CAC/D,cAAe,CACf,eAAgB,CAChB,cAAe,CACf,0BACF,CAEA,iCACE,sEACF,CAEA,6BACE,YAAa,CACb,kBAAmB,CACnB,OAAQ,CACR,MAAO,CACP,sBACF,CAEA,6BACE,cAAe,CACf,YAAa,CACb,kBACF,CAEA,6BACE,cAAe,CACf,eAAgB,CAChB,2DAA+D,CAC/D,kBACF,CAEA,gCACE,iBAAkB,CAClB,YAAa,CACb,qBAAsB,CACtB,kBAAmB,CACnB,OAAQ,CACR,aACF,CAEA,8BACE,mBAAoB,CACpB,gBAAiB,CACjB,kBAAmB,CACnB,kBACF,CAEA,6BACE,cAAe,CACf,eACF,CAEA,gCACE,UAAW,CACX,eACF,CAEA,iCACE,YAAa,CACb,6BAA8B,CAC9B,cAAe,CACf,+BAAiC,CACjC,iBACF,CAEA,+BACE,eAAgB,CAChB,mCACF,CAEA,+BACE,UAAW,CACX,UAAW,CACX,iCAAmC,CACnC,iBAAkB,CAClB,eACF,CAEA,gCACE,WAAY,CACZ,iBAAkB,CAClB,qBACF,CAEA,gCACE,mBAAoB,CACpB,aACF,CAEA,4BACE,iCAAmC,CACnC,sEAA0E,CAC1E,iBAAkB,CAClB,gBACF,CAEA,6BACE,cAAe,CACf,2DAA+D,CAC/D,iBAAkB,CAClB,YAAa,CACb,kBAAmB,CACnB,OACF,CAEA,iCACE,UAAW,CACX,WAAY,CACZ,oBAAqB,CACrB,qBACF,CAEA,6BACE,cAAe,CACf,eAAgB,CAChB,iCACF,CAEA,0BACE,UAAW,CACX,+GAAsH,CACtH,aAAc,CACd,aACF,CAEA,iCACE,MAAO,CACP,eAAgB,CAChB,YAAa,CACb,YAAa,CACb,qBAAsB,CACtB,QACF","sourcesContent":["<template>\n  <div class=\"art-page\" :style=\"cssVars\">\n    <!-- 顶部导航栏 -->\n    <div class=\"page-topbar\">\n      <button class=\"back-btn\" @click=\"handleClose\">\n        <svg viewBox=\"0 0 24 24\" width=\"18\" height=\"18\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\">\n          <polyline points=\"15 18 9 12 15 6\" />\n        </svg>\n        <span>收起百艺</span>\n      </button>\n      <div class=\"page-title\">\n        <span class=\"title-icon\" :style=\"{ color }\">\n          <slot name=\"icon\" />\n        </span>\n        <span class=\"title-name\">{{ name }}</span>\n      </div>\n      <div style=\"width: 80px;\"></div>\n    </div>\n\n    <!-- 境界信息 -->\n    <div class=\"realm-section\">\n      <div class=\"realm-badge\" :style=\"{ background: bgTint, borderColor: color }\">\n        <span class=\"realm-text\">{{ realmValue || '入门' }}</span>\n      </div>\n      <!-- 有熟练度/经验值时显示进度条 -->\n      <template v-if=\"proficiencyField\">\n        <div class=\"progress-wrap\">\n          <div class=\"progress-label\">\n            <span>熟练度</span>\n            <span class=\"progress-val\">{{ proficiencyValue }}</span>\n          </div>\n          <div class=\"progress-bar\">\n            <div class=\"progress-fill\" :style=\"{ width: Math.min(100, proficiencyValue) + '%', background: color }\" />\n          </div>\n        </div>\n        <div class=\"progress-wrap\">\n          <div class=\"progress-label\">\n            <span>经验值</span>\n            <span class=\"progress-val\">{{ expValue }}/100</span>\n          </div>\n          <div class=\"progress-bar\">\n            <div class=\"progress-fill\" :style=\"{ width: Math.min(100, expValue) + '%', background: '#f59e0b' }\" />\n          </div>\n        </div>\n      </template>\n      <!-- 额外的境界区域内容（如剑心的提示文字） -->\n      <slot name=\"realm-extra\" />\n    </div>\n\n    <!-- 额外信息区（如剑心的\"何为剑心\"说明卡片） -->\n    <slot name=\"info\" />\n\n    <!-- 工具信息 -->\n    <div class=\"tools-section\" v-if=\"toolLabel\">\n      <div class=\"tool-card\">\n        <div class=\"tool-label\">\n          <slot name=\"tool-icon\">\n            <slot name=\"icon\" />\n          </slot>\n          {{ toolLabel }}\n        </div>\n        <div class=\"tool-value\">{{ toolValue || '未装备' }}</div>\n      </div>\n    </div>\n\n    <div class=\"divider\" />\n\n    <!-- 操作区域（由各百艺自定义） -->\n    <div class=\"operation-area\">\n      <slot />\n    </div>\n\n    <!-- Picker 遮罩层 -->\n    <slot name=\"picker\" />\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { computed } from 'vue';\nimport { useStatusStore, ARTS_MAP, type ArtKey } from '../../store';\nimport type { Schema } from '../../schema';\n\nconst props = defineProps<{\n  artKey: ArtKey;\n  /** 关闭时的 toast 消息，如\"已收起炼丹\" */\n  closeToast?: string;\n}>();\n\nconst store = useStatusStore();\n\n// 从 ARTS_MAP 获取配置\nconst artConfig = computed(() => ARTS_MAP[props.artKey]);\nconst color = computed(() => artConfig.value.color);\nconst name = computed(() => artConfig.value.name);\n\n// 根据主题色生成淡底色\nconst bgTint = computed(() => {\n  // 简单方案：用 color-mix 或 固定映射\n  return `color-mix(in srgb, ${color.value} 8%, white)`;\n});\n\n// CSS 变量\nconst cssVars = computed(() => ({\n  '--art-color': color.value,\n  '--art-bg-tint': bgTint.value,\n}));\n\n// 境界\nconst realmValue = computed(() => {\n  const field = artConfig.value.境界字段;\n  if (!field) return '';\n  return (store.data[field as keyof Schema] as string) || '';\n});\n\n// 熟练度\nconst proficiencyField = computed(() => artConfig.value.熟练度字段);\nconst proficiencyValue = computed(() => {\n  const field = proficiencyField.value;\n  if (!field) return 0;\n  return (store.data[field as keyof Schema] as number) || 0;\n});\n\n// 经验值\nconst expValue = computed(() => {\n  const field = artConfig.value.经验值字段;\n  if (!field) return 0;\n  return (store.data[field as keyof Schema] as number) || 0;\n});\n\n// 工具\nconst toolLabel = computed(() => {\n  const field = artConfig.value.工具字段;\n  if (!field) return '';\n  // 从字段名提取工具标签：装备_丹炉 → 丹炉\n  return field.replace(/^装备_/, '');\n});\n\nconst toolValue = computed(() => {\n  const field = artConfig.value.工具字段;\n  if (!field) return '';\n  return (store.data[field as keyof Schema] as string) || '';\n});\n\n// 关闭\nfunction handleClose() {\n  store.closeArtsPage();\n  if (props.closeToast) {\n    toastr.info(props.closeToast);\n  } else {\n    toastr.info('已收起' + name.value);\n  }\n}\n</script>\n\n<style scoped>\n.art-page {\n  display: flex;\n  flex-direction: column;\n  height: 100%;\n  overflow: hidden;\n  background: linear-gradient(180deg, var(--art-bg-tint, #f8fafc) 0%, #fff 100%);\n}\n\n.page-topbar {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 10px 14px;\n  background: linear-gradient(135deg, var(--art-bg-tint, #f8fafc), color-mix(in srgb, var(--art-color, #64748b) 12%, white));\n  border-bottom: 1px solid color-mix(in srgb, var(--art-color, #64748b) 25%, white);\n  flex-shrink: 0;\n}\n\n.back-btn {\n  display: flex;\n  align-items: center;\n  gap: 4px;\n  padding: 4px 8px;\n  border: none;\n  border-radius: 6px;\n  background: color-mix(in srgb, var(--art-color, #64748b) 10%, transparent);\n  color: color-mix(in srgb, var(--art-color, #64748b) 80%, black);\n  font-size: 12px;\n  font-weight: 600;\n  cursor: pointer;\n  transition: background 0.2s;\n}\n\n.back-btn:hover {\n  background: color-mix(in srgb, var(--art-color, #64748b) 18%, transparent);\n}\n\n.page-title {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  flex: 1;\n  justify-content: center;\n}\n\n.title-icon {\n  font-size: 20px;\n  display: flex;\n  align-items: center;\n}\n\n.title-name {\n  font-size: 16px;\n  font-weight: 800;\n  color: color-mix(in srgb, var(--art-color, #64748b) 80%, black);\n  letter-spacing: 1px;\n}\n\n.realm-section {\n  padding: 12px 16px;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 8px;\n  flex-shrink: 0;\n}\n\n.realm-badge {\n  display: inline-flex;\n  padding: 4px 16px;\n  border-radius: 16px;\n  border: 1.5px solid;\n}\n\n.realm-text {\n  font-size: 14px;\n  font-weight: 800;\n}\n\n.progress-wrap {\n  width: 100%;\n  max-width: 300px;\n}\n\n.progress-label {\n  display: flex;\n  justify-content: space-between;\n  font-size: 11px;\n  color: var(--text-muted, #64748b);\n  margin-bottom: 3px;\n}\n\n.progress-val {\n  font-weight: 600;\n  color: var(--text-secondary, #475569);\n}\n\n.progress-bar {\n  width: 100%;\n  height: 5px;\n  background: var(--card-bg, #f1f5f9);\n  border-radius: 3px;\n  overflow: hidden;\n}\n\n.progress-fill {\n  height: 100%;\n  border-radius: 3px;\n  transition: width 0.4s;\n}\n\n.tools-section {\n  padding: 0 12px 12px;\n  flex-shrink: 0;\n}\n\n.tool-card {\n  background: var(--content-bg, #fff);\n  border: 1px solid color-mix(in srgb, var(--art-color, #64748b) 25%, white);\n  border-radius: 8px;\n  padding: 8px 10px;\n}\n\n.tool-label {\n  font-size: 11px;\n  color: color-mix(in srgb, var(--art-color, #64748b) 80%, black);\n  margin-bottom: 4px;\n  display: flex;\n  align-items: center;\n  gap: 4px;\n}\n\n.tool-label :deep(svg) {\n  width: 12px;\n  height: 12px;\n  display: inline-block;\n  vertical-align: middle;\n}\n\n.tool-value {\n  font-size: 13px;\n  font-weight: 600;\n  color: var(--text-primary, #1e293b);\n}\n\n.divider {\n  height: 1px;\n  background: linear-gradient(90deg, transparent, color-mix(in srgb, var(--art-color, #64748b) 25%, white), transparent);\n  margin: 0 12px;\n  flex-shrink: 0;\n}\n\n.operation-area {\n  flex: 1;\n  overflow-y: auto;\n  padding: 12px;\n  display: flex;\n  flex-direction: column;\n  gap: 12px;\n}\n</style>\n"],"sourceRoot":""}]);
